#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long odd = 0;
        for (int i = 0; i < N; ++i) {
            long long x; scanf("%lld", &x);
            if (x & 1LL) odd++;
        }
        long long even = N - odd;
        long long posOdd = (N + 1) / 2;
        long long posEven = N / 2;
        long long ans = (odd < posEven ? odd : posEven) + (even < posOdd ? even : posOdd);
        printf("%lld\n", ans);
    }
    return 0;
}

